import { useState, useMemo, useEffect, useRef } from "react";
import data from "../data/portfolio.json";

export default function usePortfolio(favorites = []) {
  const { items: rawItems, dicts } = data;
  const { temas, tags, usos } = dicts;

  const [query, setQuery] = useState("");
  const [category, setCategory] = useState("todas");
  const [filters, setFilters] = useState([]);
  const [selected, setSelected] = useState(null);
  const [page, setPage] = useState(1);

  const pageSize = 24;

  // 🔧 NORMALIZACIÓN
  const items = useMemo(() => {
    return rawItems.map((item) => {
      const temasLabels = item.meta.temas.map((i) => temas[i]);
      const tagsLabels = item.meta.tags.map((i) => tags[i]);
      const usosLabels = item.meta.usos.map((i) => usos[i]);

      const allFilters = [...temasLabels, ...tagsLabels, ...usosLabels];
      const allFiltersLower = allFilters.map((f) => f.toLowerCase());

      let categoria = item.categoria;
      if (categoria === "otros") {
        if (item.id.startsWith("ilu-")) categoria = "ilustracion";
        if (item.id.startsWith("dis-")) categoria = "diseno";
      }

      return {
        ...item,
        categoria,
        allFilters,
        allFiltersLower,
      };
    });
  }, [rawItems, temas, tags, usos]);

  // 🔍 FILTROS
  const normalizedFilters = useMemo(
    () => filters.map((f) => f.toLowerCase()),
    [filters]
  );

  const favoritesFilterActive = normalizedFilters.includes("__favoritos__");
  const cleanFilters = normalizedFilters.filter((f) => f !== "__favoritos__");

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();

    const result = items.filter((item) => {
      if (!favoritesFilterActive && category !== "todas" && item.categoria !== category) return false;

      if (
        q &&
        !item.titulo.toLowerCase().includes(q) &&
        !item.allFiltersLower.some((f) => f.includes(q))
      )
        return false;

      if (
        cleanFilters.length &&
        !cleanFilters.some((f) => item.allFiltersLower.includes(f))
      )
        return false;

      if (favoritesFilterActive && !favorites.includes(item.id)) return false;

      return true;
    });

    return result;
  }, [items, query, category, normalizedFilters, favorites]);

  // 📄 PAGINACIÓN
  const paginated = useMemo(() => {
    const start = (page - 1) * pageSize;
    return filtered.slice(start, start + pageSize);
  }, [filtered, page]);

  // 🔁 RESET PAGE cuando cambian filtros
useEffect(() => {
  console.log("🔴 RESET PAGE a 1 - query:", query, "category:", category, "filters:", filters);
  setPage(1);
}, [query, category, filters]);

  const filteredLengthRef = useRef(filtered.length);

useEffect(() => {
  const newLength = filtered.length;
  const oldLength = filteredLengthRef.current;
  console.log("🟡 AJUSTE PAGE - newLength:", newLength, "oldLength:", oldLength, "page:", page);

  if (newLength !== oldLength) {
    const maxPage = Math.max(1, Math.ceil(newLength / pageSize));
    console.log("🟡 maxPage:", maxPage, "page > maxPage?", page > maxPage);
    if (page > maxPage) setPage(maxPage);
    filteredLengthRef.current = newLength;
  }
}, [filtered.length, page, pageSize]);

  // 🎯 SELECTED seguro
  useEffect(() => {
    if (!filtered.length) {
      setSelected(null);
      return;
    }

    const exists = filtered.some((i) => i.id === selected?.id);
    if (!exists) setSelected(filtered[0]);
  }, [filtered]);

  // ¿Hay búsqueda o filtros activos?
  const hasActiveSearch = query.trim() !== "" || filters.length > 0 || category !== "todas";

  return {
    query,
    setQuery,
    category,
    setCategory,
    filters,
    setFilters,
    selected,
    setSelected,
    page,
    setPage,
    items,
    filtered,
    paginated,
    pageSize,
    temas,
    tags,
    usos,
    hasActiveSearch,
  };
}
